SELECT [NavisionEan-step0].[Cross-Reference No_] AS EANCode, [NavisionEan-step0-UPC].[Cross-Reference No_] AS UPCCode, Item.No_ AS Item, Item.[Model Item No_] AS Article, Item.[Description 2], Item.[Variable Code 01] AS Color, [Variable Code].Description AS ColorDesc, Item.[Variable Code 02] AS [Size], Item.[Season Code], Item.[Trademark Code], Item.[Collection Code], Item.[Sales_Purchase Status - Item], Sum(SalesLineTMP.qty) AS TotalQuantity, SalesLineTMP.[Customer NO_], First(SalesLineTMP.[Customer Name]) AS [Customer Name]
FROM ((SalesLineTMP LEFT JOIN (Item LEFT JOIN [NavisionEan-step0] ON Item.No_ = [NavisionEan-step0].[Item No_]) ON SalesLineTMP.NO_ = Item.No_) LEFT JOIN [Variable Code] ON (Item.[Variable Code 01] = [Variable Code].[Variable Code]) AND (Item.[Variable Group 01] = [Variable Code].[Variable Group])) LEFT JOIN [NavisionEan-step0-UPC] ON Item.No_ = [NavisionEan-step0-UPC].[Item No_]
WHERE (((Item.[Advertising Material])=0) AND ((Item.[Configurator Relation])=3))
GROUP BY [NavisionEan-step0].[Cross-Reference No_], [NavisionEan-step0-UPC].[Cross-Reference No_], Item.No_, Item.[Model Item No_], Item.[Description 2], Item.[Variable Code 01], [Variable Code].Description, Item.[Variable Code 02], Item.[Season Code], Item.[Trademark Code], Item.[Collection Code], Item.[Sales_Purchase Status - Item], SalesLineTMP.[Customer NO_];

